#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        S = list(next(it))
        sorted_s = sorted(S)
        ok = True
        for i in range(N // 2):
            a, b = S[i], S[N - 1 - i]
            c, d = sorted_s[i], sorted_s[N - 1 - i]
            if not ((a == c and b == d) or (a == d and b == c)):
                ok = False
                break
        if N % 2 == 1 and S[N // 2] != sorted_s[N // 2]:
            ok = False
        out.append("YES" if ok else "NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

