const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const S = input[idx++].split('');
  const sorted = [...S].sort();
  let ok = true;
  for (let i = 0; i < Math.floor(N / 2) && ok; i++) {
    const a = S[i], b = S[N - 1 - i];
    const c = sorted[i], d = sorted[N - 1 - i];
    if (!((a === c && b === d) || (a === d && b === c))) ok = false;
  }
  if (N % 2 === 1 && S[Math.floor(N / 2)] !== sorted[Math.floor(N / 2)]) ok = false;
  results.push(ok ? 'YES' : 'NO');
}
